using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tipo de mensagem de tutorial — determina posicionamento, confirmação e
/// capacidades visuais.
/// </summary>
public enum TutorialMessageType
{
    /// <summary>
    /// Aparece no centro da tela. Pausa o jogo. Suporta imagem acima do texto.
    /// Texto longo rola ao pressionar "Continuar". Requer confirmação do player
    /// para fechar.
    /// </summary>
    Importante,

    /// <summary>
    /// Aparece perto de um elemento da HUD (posição configurada em runtime).
    /// Requer confirmação do player para fechar. Sem imagem.
    /// </summary>
    Media,

    /// <summary>
    /// Pop-up pequeno no topo da tela. Não exige confirmação — some
    /// automaticamente após <see cref="TutorialMessageManager.toastDuration"/> segundos.
    /// Não bloqueia o jogo.
    /// </summary>
    NaoImportante,
}

/// <summary>
/// Pedido de mensagem de tutorial enfileirado.
/// </summary>
public class TutorialMessageRequest
{
    /// <summary>Tipo da mensagem (Importante / Media / NaoImportante).</summary>
    public TutorialMessageType type;

    /// <summary>Texto principal da mensagem.</summary>
    public string text;

    /// <summary>
    /// Imagem exibida ACIMA do texto (só usada em Tipo Importante).
    /// Ex: sprite com os movimentos do animal recém-desbloqueado.
    /// </summary>
    public Sprite image;

    /// <summary>
    /// Posição de ancoragem em viewport/canvas local (usado por Tipo Média
    /// para posicionar perto de um elemento da HUD).
    /// Ignorado em Importante e NaoImportante.
    /// </summary>
    public Vector2 anchorPosition;

    /// <summary>
    /// Callback disparado quando a mensagem é confirmada/fechada.
    /// Útil para encadear lógica após o player confirmar um tutorial.
    /// </summary>
    public System.Action onConfirmed;
}

/// <summary>
/// Gestor de Mensagens de Tutorial — exibe avisos contextuais ao player em
/// três formatos distintos, com filas separadas para mensagens que requerem
/// confirmação (Importante / Média) e mensagens não-bloqueantes (NaoImportante).
///
/// <b>Três tipos:</b>
/// <list type="bullet">
///   <item><b>Importante</b>: centro do ecrã, pausa o jogo, suporta imagem
///     acima do texto, texto longo rola ao pressionar "Continuar", requer
///     confirmação. Usado para revelar movimentos de novos animais, avisos
///     críticos do jogo, tutorial do Jukebox, etc.</item>
///   <item><b>Média</b>: aparece perto de um elemento da HUD (posição
///     configurada via anchorPosition), requer confirmação, sem imagem.</item>
///   <item><b>Não Importante</b>: pop-up pequeno no topo do ecrã, sem
///     confirmação, some automaticamente. Não bloqueia o jogo nem interrompe
///     o fluxo. Nunca sobrepõe a HUD principal (posicionamento via UI).</item>
/// </list>
///
/// <b>Uso:</b>
/// <code>
/// // Importante com imagem:
/// TutorialMessageManager.Instance.Show(new TutorialMessageRequest {
///     type    = TutorialMessageType.Importante,
///     text    = "Este animal pode nadar e mergulhar!\n...",
///     image   = animalMovesSprite,
///     onConfirmed = () => { /* continua fluxo */ }
/// });
///
/// // Não importante (toast):
/// TutorialMessageManager.Instance.ShowToast("Melodia selvagem encontrada!");
/// </code>
///
/// <b>Montagem no Editor:</b> ligar <see cref="TutorialMessageUI"/> como
/// referência — este manager apenas enfileira e coordena; a UI faz o render.
/// </summary>
public class TutorialMessageManager : MonoBehaviour
{
    public static TutorialMessageManager Instance { get; private set; }

    [Header("UI (ligar TutorialMessageUI na cena)")]
    [Tooltip("Componente de UI que renderiza as mensagens de tutorial.")]
    [SerializeField] private TutorialMessageUI ui;

    [Header("Toast (Não Importante)")]
    [Tooltip("Duração (s) que um toast fica visível antes de desaparecer.")]
    [SerializeField] public float toastDuration = 2.5f;

    [Tooltip("Som tocado ao mostrar qualquer mensagem de tutorial.")]
    [SerializeField] private AudioClip defaultSfx;

    // Fila de mensagens que requerem confirmação (Importante / Média).
    private readonly Queue<TutorialMessageRequest> _confirmQueue = new Queue<TutorialMessageRequest>();
    private bool _showingConfirm;

    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
                Destroy(Instance.gameObject);
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(TutorialMessageManager) + " (Fallback)");
        var inst = go.AddComponent<TutorialMessageManager>();
        inst.isAutoFallback = true;
    }

    // ==================== API Pública ====================

    /// <summary>
    /// Enfileira uma mensagem de tutorial. Mensagens Importantes e Médias são
    /// exibidas em sequência (nunca sobrepostas). NaoImportante são exibidas
    /// imediatamente como toast independente.
    /// </summary>
    public void Show(TutorialMessageRequest request)
    {
        if (request == null) return;

        if (request.type == TutorialMessageType.NaoImportante)
        {
            PlaySfx();
            if (ui != null)
                StartCoroutine(ui.ShowToastRoutine(request.text, toastDuration));
            return;
        }

        _confirmQueue.Enqueue(request);
        if (!_showingConfirm)
            StartCoroutine(ProcessConfirmQueueRoutine());
    }

    /// <summary>Atalho para mostrar um toast (Não Importante) só com texto.</summary>
    public void ShowToast(string text)
    {
        Show(new TutorialMessageRequest
        {
            type = TutorialMessageType.NaoImportante,
            text = text
        });
    }

    /// <summary>
    /// Atalho para mostrar uma mensagem Importante com imagem e callback.
    /// O jogo é pausado até o player confirmar.
    /// </summary>
    public void ShowImportant(string text, Sprite image = null, System.Action onConfirmed = null)
    {
        Show(new TutorialMessageRequest
        {
            type        = TutorialMessageType.Importante,
            text        = text,
            image       = image,
            onConfirmed = onConfirmed,
        });
    }

    /// <summary>Atalho para mostrar uma mensagem Média (sem imagem, com confirmação).</summary>
    public void ShowMedia(string text, Vector2 anchorPosition = default, System.Action onConfirmed = null)
    {
        Show(new TutorialMessageRequest
        {
            type           = TutorialMessageType.Media,
            text           = text,
            anchorPosition = anchorPosition,
            onConfirmed    = onConfirmed,
        });
    }

    // ==================== Fila de Confirmação ====================

    private IEnumerator ProcessConfirmQueueRoutine()
    {
        _showingConfirm = true;

        while (_confirmQueue.Count > 0)
        {
            var request = _confirmQueue.Dequeue();
            PlaySfx();

            bool confirmed = false;
            System.Action onDone = () =>
            {
                confirmed = true;
                request.onConfirmed?.Invoke();
            };

            if (ui != null)
            {
                yield return ui.ShowConfirmRoutine(request, onDone);
            }
            else
            {
                // Sem UI: aguarda um frame (não bloqueia indefinidamente).
                yield return null;
                onDone();
            }

            // Garante que confirmou antes de processar o próximo.
            while (!confirmed)
                yield return null;
        }

        _showingConfirm = false;
    }

    // ==================== Helpers ====================

    private void PlaySfx()
    {
        if (defaultSfx != null)
            AudioManager.Instance?.PlaySE(defaultSfx);
    }
}
